<template>
    <div class="start-block">
        <div class="start-block__title">
            <p>коллекция</p>
            <span>весна - лето</span>
            <p>2020-2021</p>
        </div>
        <a href=""
            class="linkBtn"
            id="showRegisterForm" 
            v-on:click.prevent = "showRegisterBlock"    
        >START</a>
    </div>
</template>
<script>

export default {
    methods: {
        showRegisterBlock(){
            if(localStorage.getItem('userID') !== null){
                this.$router.push('Registration');
                console.log(this.$store.getters.test)
            }else{
                $(".start-block").addClass('hideBlock');
                $(".register-block").addClass('showBlock');
                $(".shadow-block").addClass("show");
            }
        }
    }, 
    created(){
        if(localStorage.getItem('userID') !== null){
            this.$store.dispatch('GET_USER_INFO')
        }
    }
    
}
</script>