<template>
    <div class="register-block">
        <form class="signForm">
            <div class="form__title">авторизация</div>
            <input 
                type="text" 
                name="Email" 
                v-model.trim="email"
                :class="{error: ($v.email.$dirty && !$v.email.required) || ($v.email.$dirty && !$v.email.email)}"
                placeholder="E-mail">
                <label 
                    class="error"
                    v-if="$v.email.$dirty && !$v.email.required">
                    Поле 'E-mail' не должно быть пустым
                </label>
                <label 
                    class="error"
                    v-else-if="$v.email.$dirty && !$v.email.email">
                    Введите корректный e-mail
                </label>
            <input 
                type="password" 
                name="password"
                v-model.trim="password" 
                :class="{error: ($v.password.$dirty && !$v.password.required) || ($v.password.$dirty && !$v.password.minLength)}"
                placeholder="Пороль">
                <label 
                    class="error"
                    v-if="$v.password.$dirty && !$v.password.required">
                    Поле 'Пороль' не должно быть пустым
                </label>
                <label 
                    class="error"
                    v-else-if="$v.password.$dirty && !$v.password.minLength">
                    Пароль должен быть не меньше 6 символов
                </label>
            <input 
                type="submit"
                value="войти" 
                id="register"
                v-on:click.prevent = "sendForm">
        </form>
    </div>
</template>
<script>
import {email, required, minLength} from 'vuelidate/lib/validators'; //валидатор
export default {
    name: 'registerBlock',
    data: () => ({
        email: '',
        password: '',  
    }),
    validations: {
        email: {email, required},
        password: {required, minLength: minLength(6)}
    },
    methods: {
        logIn(){
            
        },
        sendForm(){
            if(this.$v.$invalid){
                this.$v.$touch()
                return
                
            }else{
                // let data = {
                //     'login': this.email,
                //     'password': this.password
                // }
                let data = {
                    'login': 'Alexander.burzev@gmail.com',
                    'password': '1qazXSW@3edcVFR$'
                }


                // login: test@test.ua
                // pass: test@test.ua


                this.$store.dispatch('LOGIN', data)
                    .then(resp => {
                        this.makeToast('Поздравляем!', 'success', 'Вы авторизация прошла успешно!');
                        setTimeout(() => {this.$router.push('Registration')}, 1500)

                        }).catch(err => this.makeToast('Ошибка!', 'danger', 'Неправильный логин или пароль'))                            
            }
        },
        makeToast(title, variant, text,  append = false) {
            this.$bvToast.toast(text, {
                title: title,
                autoHideDelay: 3000,
                variant: variant,
                toaster: 'b-toaster-top-center',
                appendToast: append
            })
        }   
    }
}
</script>